DELETE FROM vehicle WHERE vehicle_model_id NOT BETWEEN 1 AND 65;
DELETE FROM vehicle_model WHERE id NOT BETWEEN 1 AND 65;
SET FOREIGN_KEY_CHECKS=1;

-- Vehicle models (IDs explícitos para que vehicle.vehicle_model_id siempre coincida)
ON DUPLICATE KEY UPDATE vehicle_brand_id=VALUES(vehicle_brand_id), name=VALUES(name);
ALTER TABLE vehicle_model AUTO_INCREMENT = 66;

