--
-- Transactions: generadas dinámicamente usando estaciones reales del CNE sync.
-- Spring ejecuta esto en cada arranque; INSERT IGNORE + NOT EXISTS evita duplicados.
-- Si station está vacía (sin CNE sync aún), los inserts se omiten sin error.
--
    `id`, `created_at`, `updated_at`, `discount_amount`, `final_amount`,
    `gross_amount`, `liters`, `notes`, `transaction_date`, `unit_price`,
    `card_product_id`, `discount_id`, `fuel_type_id`, `station_id`,
    `user_id`, `vehicle_id`, `deleted_at`
)
SELECT
    UUID(), tx_date, tx_date, discount,
    ROUND(liters * unit_price, 2) - discount,
    ROUND(liters * unit_price, 2),
    liters, NULL, tx_date, unit_price,
    NULL, NULL, fuel_type_id,
    (SELECT id FROM station ORDER BY RAND() LIMIT 1),
    user_id, vehicle_id, NULL
FROM (
    SELECT
        v.id AS vehicle_id, v.user_id, v.fuel_type_id,
        DATE_SUB(NOW(), INTERVAL (seq.n * 26 + FLOOR(RAND() * 10)) DAY) AS tx_date,
        20 + FLOOR(RAND() * 30) + ROUND(RAND(), 1) AS liters,
        CASE v.fuel_type_id
            WHEN 1 THEN 930  + FLOOR(RAND() * 80)
            WHEN 2 THEN 960  + FLOOR(RAND() * 80)
            WHEN 3 THEN 1040 + FLOOR(RAND() * 80)
            WHEN 4 THEN 820  + FLOOR(RAND() * 60)
            ELSE         950 + FLOOR(RAND() * 80)
        END AS unit_price,
        IF(RAND() > 0.4, 4900, 0) AS discount
    FROM vehicle v
    JOIN `user` u ON u.id = v.user_id
    CROSS JOIN (
        SELECT 0 AS n UNION ALL SELECT 1 UNION ALL SELECT 2
        UNION ALL SELECT 3 UNION ALL SELECT 4 UNION ALL SELECT 5
    ) seq
    WHERE u.role_id = 2
      AND NOT EXISTS (SELECT 1 FROM `transaction` t2 WHERE t2.vehicle_id = v.id)
      AND EXISTS     (SELECT 1 FROM station LIMIT 1)
) calc;


